type_definitions:
// src/lib/types.ts:25
export type Instrument = "piano" | "guitar";

// src/lib/types.ts:111-115
export type KeyId =
  | "C" | "G" | "D" | "A" | "E" | "B" | "Fs" | "Cs"
  | "F" | "Bb" | "Eb" | "Ab" | "Db" | "Gb"
  | "am" | "em" | "bm" | "fsm" | "csm" | "gsm" | "dsm" | "asm"
  | "dm" | "gm" | "cm" | "fm" | "bbm" | "ebm";
// 24-member CLOSED union (12 majors + 12 relative minors). Backed 1:1 by
// src/lib/music.ts KEY_META: Record<KeyId, {name, tonic, mode, sharpsFlats, relative}>
// -- an exhaustive object literal, so every KeyId member MUST have a real
// tonic/mode entry. There is no runtime validation beyond this; indexing
// KEY_META with a fabricated/un-registered string cast as KeyId returns
// undefined and the very next `.tonic`/`.mode` access throws at render time.

// src/lib/instrumentRegistry.ts:86-91 (fields inside InstrumentModule)
/** What a weekly "focus" is for this instrument. piano = "key", guitar = "chord". */
focusKind: "key" | "chord";
/** Map a focus id (a KeyId for piano, a chord/riff id for guitar) -> display label. */
focusLabel: (focusId: string) => string;
/** Which progress-map visual the /tree page should render for this instrument. */
progressMapKind: "keymap" | "fretboard";
